import { Col, Row, Select } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import SpanText from "src/components/Typography/SpanText"
import { hideOnSinglePage, SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey, getSystemKeyDescription } from "src/lib/utils"
import MembershipPackageService from "src/services/MembershipPackageService"
import ModalDetailPackage from "./modal/ModalDetailPackage"
import { MembershipStyled } from "./styled"

const { Option } = Select

const MembershipPackage = () => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
    Status: "",
    RankObject: "",
  })
  const [textSearch, setTextSearch] = useState("")
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState([])
  const [totalRecords, setTotalRecords] = useState(0)
  const [openModalInsertUpdate, setOpenModalInsertUpdate] = useState(false)

  const columns = [
    {
      title: "STT",
      dataIndex: "index",
      render: (_, __, idx) =>
        idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1),
      width: 70,
      align: "center",
    },
    {
      title: "Tên quyền",
      dataIndex: "RankName",
      width: 400,
    },
    {
      title: "Đối tượng",
      dataIndex: "RankObject",
      align: "center",
      render: val => (val ? getRankObjectName(val) : "-"),
    },
    {
      title: "Chiết khấu",
      dataIndex: "RankDiscount",
      align: "center",
      render: val => (val ? `${val}%` : "-"),
    },

    // {
    //   title: "Giá",
    //   dataIndex: "RankPrice",
    //   align: "right",
    //   width: 160,
    //   render: val => formatPrice(val),
    // },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      align: "center",
      width: 160,
      render: (isStatus, record) => {
        const statusName = getStatusName(isStatus)
        const isActive = isStatus === 1

        return (
          <div>
            <div className="fw-600">
              <SpanText type={isActive ? "success" : "danger"}>
                {statusName}
              </SpanText>
            </div>

            <FloatActionWrapper size="small" className="float-action__wrapper">
              <ButtonCircle
                className="button-circle"
                title="Chỉnh sửa"
                iconName="edit"
                style={{
                  background: "#EDF6FC",
                  boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                }}
                onClick={e => {
                  e.stopPropagation()
                  setOpenModalInsertUpdate(record)
                }}
              />
              <ButtonCircle
                className="button-circle"
                title="Xoá"
                iconName="deleteRow"
                style={{
                  background: "#FFE9EC",
                  boxShadow: "0px 2px 4px rgba(208, 206, 187, 0.5)",
                }}
                onClick={e => {
                  e.stopPropagation()
                  handleDeleteConfirm(record)
                }}
              />
            </FloatActionWrapper>
          </div>
        )
      },
    },
  ]
  const getStatusName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.STATUS, value, listSystemKey)

  const getRankObjectName = value =>
    getSystemKeyDescription(SYSTEM_KEY?.RANK_OBJECT, value, listSystemKey)

  // const getDurationUnitText = value =>
  //   getSystemKeyDescription(SYSTEM_KEY?.DURATION_UNIT, value, listSystemKey)

  const getList = async () => {
    try {
      setLoading(true)
      const params = {
        TextSearch: textSearch.trim(),
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
      }
      if (pagination.Status) params.Status = Number(pagination.Status)

      if (pagination.RankObject)
        params.RankObject = Number(pagination.RankObject)

      const res = await MembershipPackageService.getListRank(params)
      if (res?.isError) return

      const { ListData = [], TotalCount = 0 } = res?.Object || {}
      setListData(ListData)
      setTotalRecords(TotalCount)
    } finally {
      setLoading(false)
    }
  }

  const deleteRank = async id => {
    try {
      const res = await MembershipPackageService.deleteRank({
        memberRankID: id,
      })
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Xóa quyền thành viên thành công!",
      })
    } catch {
      console.log("Có lỗi xảy ra khi xóa quyền thành viên.")
    }
  }

  const handleDeleteConfirm = record => {
    CB1({
      title: `Bạn có chắc chắn muốn xoá quyền <strong>"${record.RankName}"</strong> không?`,
      icon: "warning-usb",
      okText: "Đồng ý",
      cancelText: "Hủy",
      width: 500,
      warningTitle: true,
      okButtonProps: {
        style: {
          background: "#ff4d4f",
          borderColor: "#ff4d4f",
        },
      },
      onOk: close => {
        deleteRank(record.MemberRankID)
        close()
      },
    })
  }

  useEffect(() => {
    if (pagination) getList()
  }, [pagination])
  useEffect(() => {
    const timeoutId = setTimeout(() => {
      setPagination(prev => ({
        ...prev,
        textSearch: textSearch,
        CurrentPage: 1,
      }))
    }, 300)

    return () => clearTimeout(timeoutId)
  }, [textSearch])

  return (
    <SpinCustom spinning={loading}>
      <MembershipStyled>
        <Row className="title-type-1 justify-content-space-between align-items-center ">
          <div style={{ fontSize: 24 }}>
            Danh sách quyền hội viên ({totalRecords}):
          </div>
          <ButtonCustom
            btnType="primary"
            className="btn-hover-shadow"
            onClick={() => setOpenModalInsertUpdate(true)}
          >
            Thêm mới
          </ButtonCustom>
        </Row>
        <Row
          className="align-items-center pb-8 pt-0 mb-16 mt-16"
          gutter={[16, 16]}
          align="middle"
        >
          <Col flex="1 1 400px" style={{ minWidth: "300px" }}>
            <InputCustom
              type="search"
              allowClear
              label="Tìm kiếm theo tên quyền"
              enterButton
              onSearch={() =>
                setPagination(pre => ({ ...pre, CurrentPage: 1 }))
              }
              onChange={e => setTextSearch(e?.target?.value)}
            />
          </Col>
          <Col flex="0 0 200px">
            <SelectCustom
              label="Đối tượng"
              value={pagination.RankObject}
              onChange={RankObject => {
                setPagination(pre => ({
                  ...pre,
                  RankObject,
                  CurrentPage: 1,
                }))
              }}
            >
              <Option value="">Tất cả</Option>
              {getListComboByKey(SYSTEM_KEY?.RANK_OBJECT, listSystemKey)?.map(
                i => (
                  <Option key={i.CodeValue} value={i.CodeValue}>
                    {i.Description}
                  </Option>
                ),
              )}
            </SelectCustom>
          </Col>
          <Col flex="0 0 180px">
            <SelectCustom
              label="Trạng thái"
              value={pagination.Status}
              onChange={Status => {
                setPagination(pre => ({ ...pre, Status, CurrentPage: 1 }))
              }}
            >
              <Option value="">Tất cả</Option>
              {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(i => (
                <Option key={i.CodeValue} value={i.CodeValue}>
                  {i.Description}
                </Option>
              ))}
            </SelectCustom>
          </Col>
        </Row>

        <TableCustom
          isPrimary
          dataSource={listData}
          columns={columns}
          sticky={{ offsetHeader: -12 }}
          loading={loading}
          textEmpty="Không có quyền hội viên nào!"
          pagination={{
            hideOnSinglePage: totalRecords <= hideOnSinglePage,
            current: pagination?.CurrentPage,
            pageSize: pagination?.PageSize,
            responsive: true,
            total: totalRecords,
            locale: { items_per_page: "" },
            showSizeChanger: true,
            onChange: (CurrentPage, PageSize) => {
              setPagination({
                ...pagination,
                CurrentPage,
                PageSize,
              })
            },
          }}
          rowKey="MemberRankID"
          onRow={record => ({
            onClick: () => {
              setOpenModalInsertUpdate({ ...record, isViewMode: true })
            },
          })}
        />

        {openModalInsertUpdate && (
          <ModalDetailPackage
            open={openModalInsertUpdate}
            onOk={getList}
            onCancel={() => setOpenModalInsertUpdate(false)}
          />
        )}
      </MembershipStyled>
    </SpinCustom>
  )
}

export default MembershipPackage
