import { Checkbox, Col, Form, Radio, Row, Select, Spin } from "antd"
import { useEffect, useState } from "react"
import InputCustom from "src/components/Input/InputCustom"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import MembershipPackageService from "src/services/MembershipPackageService"
import { getListComboByKey } from "src/lib/utils"
import { useSelector } from "react-redux"
import CheckboxCustom from "src/components/CheckboxCustom"
import SelectCustom from "src/components/Select/SelectCustom"
import { SYSTEM_KEY } from "src/constants/constants"

function ModalDetailPackage({ open, onCancel, onOk }) {
  const [form] = Form.useForm()
  const [loading, setLoading] = useState(false)
  const { listSystemKey } = useSelector(state => state.appGlobal)

  const isViewMode = open?.isViewMode
  const isEditMode = open?.MemberRankID && !isViewMode

  const handleSubmit = async () => {
    if (isViewMode) return

    try {
      setLoading(true)
      const values = await form.validateFields()
      const formattedValues = {
        ...values,
        // RankPrice: Number(values.RankPrice),
        // RankDuration: Number(values.RankDuration),
        // DurationUnit: Number(values.DurationUnit),
        RankObject: Number(values.RankObject) || 0,
        RankDiscount: Number(values.RankDiscount) || 0,
        RankInterest: values.RankInterest || "",
        Status: values.Status ? 1 : 2,
        ...(isEditMode && { MemberRankID: open.MemberRankID }),
      }
      let response

      if (isEditMode) {
        response = await MembershipPackageService.updateRank(formattedValues)
      } else {
        response = await MembershipPackageService.insertRank(formattedValues)
      }

      if (response?.isError) return

      Notice({
        msg: isEditMode
          ? "Cập nhật quyền thành công"
          : "Thêm mới quyền thành công",
        isSuccess: true,
      })
      onOk()
      onCancel()
    } catch (error) {
      console.log("Validation failed:", error)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (open?.MemberRankID) {
      form.setFieldsValue({
        ...open,
        RankObject: Number(open.RankObject),
        Status: open.Status === 1,
      })
    } else {
      form.resetFields()
    }
  }, [open, form])

  return (
    <CustomModal
      title={
        isViewMode
          ? "Chi tiết quyền thành viên"
          : isEditMode
          ? "Sửa thông tin quyền"
          : "Thêm quyền thành viên"
      }
      open={!!open}
      width={720}
      onCancel={onCancel}
      footer={
        !isViewMode && (
          <div style={{ display: "flex", justifyContent: "flex-end", gap: 8 }}>
            <Button btnType="secondary" onClick={onCancel}>
              Hủy
            </Button>
            <Button btnType="primary" onClick={handleSubmit} loading={loading}>
              {isEditMode ? "Cập nhật" : "Thêm mới"}
            </Button>
          </div>
        )
      }
    >
      <Spin spinning={loading}>
        <Form form={form} layout="vertical" disabled={isViewMode}>
          <Row gutter={[16, 16]}>
            <Col span={24}>
              <Form.Item
                name="RankName"
                label="Tên quyền"
                rules={[
                  { required: true, message: "Tên quyền không được để trống!" },
                  {
                    max: 255,
                    message: "Tên quyền không được vượt quá 255 ký tự!",
                  },
                ]}
              >
                <InputCustom placeholder="Nhập tên quyền" />
              </Form.Item>
            </Col>

            {/* <Col span={12}>
              <Form.Item
                name="RankPrice"
                label="Giá (VNĐ)"
                rules={[
                  { required: true, message: "Giá không được để trống!" },
                  {
                    validator: (_, value) =>
                      value && value <= 0
                        ? Promise.reject(new Error("Giá phải lớn hơn 0!"))
                        : Promise.resolve(),
                  },
                ]}
              >
                <InputCustom
                  type="number"
                  placeholder="Nhập giá"
                  min={1}
                  formatter={(value) => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ",")}
                />
              </Form.Item>
            </Col> */}

            <Col span={12}>
              <Form.Item
                name="RankDiscount"
                label="Mức chiết khấu (%)"
                rules={[
                  // {
                  //   required: true,
                  //   message: "Mức chiết khấu không được để trống!",
                  // },
                  {
                    validator: (_, value) =>
                      value && (value < 0 || value > 100)
                        ? Promise.reject(
                            new Error("Chiết khấu phải từ 0-100%!"),
                          )
                        : Promise.resolve(),
                  },
                ]}
              >
                <InputCustom type="number" placeholder="Nhập % chiết khấu" />
              </Form.Item>
            </Col>

            {/* <Col span={12}>
              <Form.Item
                name="RankDuration"
                label="Thời hạn"
                rules={[
                  { required: true, message: "Thời hạn không được để trống!" },
                  {
                    validator: (_, value) =>
                      value && value <= 0
                        ? Promise.reject(new Error("Thời hạn phải lớn hơn 0!"))
                        : Promise.resolve(),
                  },
                ]}
              >
                <InputCustom type="number" placeholder="Nhập thời hạn" min={1} />
              </Form.Item>
            </Col>

            <Col span={12}>
              <Form.Item
                name="DurationUnit"
                label="Đơn vị thời hạn"
                rules={[{ required: true, message: "Vui lòng chọn đơn vị thời hạn!" }]}
              >
                <SelectCustom placeholder="Chọn đơn vị thời hạn">
                  {getListComboByKey("DURATION_UNIT", listSystemKey)?.map((item) => (
                    <SelectCustom.Option key={item.ID} value={Number(item.CodeValue)}>
                      {item.Description}
                    </SelectCustom.Option>
                  ))}
                </SelectCustom>
              </Form.Item>
            </Col> */}
            <Col span={12}>
              <Form.Item name="RankObject" label="Đối tượng">
                <SelectCustom placeholder="Chọn đối tượng" allowClear>
                  {getListComboByKey(
                    SYSTEM_KEY?.RANK_OBJECT,
                    listSystemKey,
                  )?.map(item => (
                    <SelectCustom.Option
                      key={item.ID}
                      value={Number(item.CodeValue)}
                    >
                      {item.Description}
                    </SelectCustom.Option>
                  ))}
                </SelectCustom>
              </Form.Item>
            </Col>

            <Col span={12}>
              <Form.Item
                name="Status"
                label="Trạng thái"
                valuePropName="checked"
              >
                <CheckboxCustom disabled={isViewMode}>Kích hoạt</CheckboxCustom>
              </Form.Item>
            </Col>

            <Col span={24}>
              <Form.Item name="RankInterest" label="Quyền lợi">
                <InputCustom
                  type="textarea"
                  placeholder="Nhập mô tả quyền lợi"
                  style={{ height: 120, overflow: "hidden auto" }}
                />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Spin>
    </CustomModal>
  )
}

export default ModalDetailPackage
